const occ = $('Airtable - Occupancy').first().json.records || [];
const inv = $('Airtable - Inventory').first().json.records || [];
const history = $('Airtable - PO History').first().json.records || [];

const occFormatted = occ.map(r => {
  const date = r.fields.Date || r.fields.Name || 'Unknown';
  const pct = r.fields['Occupancy %'] ? Math.round(r.fields['Occupancy %'] * 100) : 'N/A';
  const events = r.fields.Events || 'no events';
  return date + ': ' + pct + '% (' + events + ')';
}).join('\n') || 'No forecast data';

const avgOcc = occ.length > 0 ? Math.round(occ.reduce((s,r) => s + ((r.fields['Occupancy %'] || 0.75) * 100), 0) / occ.length) : 75;

const invFormatted = inv.map(r => r.fields.Name + ': current=' + (r.fields['Current Stock'] || 0) + ' ' + (r.fields.Unit || '') + ', par=' + (r.fields['Par Level'] || 0)).join('\n') || 'No inventory data';

const events = occ.filter(r => r.fields.Events && r.fields.Events.trim()).map(r => (r.fields.Date || r.fields.Name) + ': ' + r.fields.Events).join('\n') || 'No special events';

const historyTotal = history.reduce((s,r) => s + (r.fields.total_amount || 0), 0);
const weeksOfData = Math.max(1, Math.ceil(history.length / 7));

const today = new Date();
const nextMon = new Date(today); nextMon.setDate(today.getDate() + (1 + 7 - today.getDay()) % 7);
const nextSun = new Date(nextMon); nextSun.setDate(nextMon.getDate() + 6);

return [{ json: {
  property_name: 'Hotel Jadran', total_rooms: 200,
  week_start: nextMon.toISOString().split('T')[0],
  week_end: nextSun.toISOString().split('T')[0],
  daily_occupancy_formatted: occFormatted,
  avg_occupancy: avgOcc,
  events_formatted: events,
  historical_sales_formatted: 'Avg weekly PO value: €' + Math.round(historyTotal / weeksOfData),
  current_inventory_formatted: invFormatted
} }];

const r = $input.first().json;
let content = r.choices[0].message.content;

// Clean markdown fences if present
content = content.replace(/```json|```/g, '').trim();

// If response was truncated (finish_reason=length), try to repair the JSON
const finishReason = r.choices[0].finish_reason;
if (finishReason === 'length') {
  // Try to close any open strings/objects/arrays
  let depth = 0;
  let inString = false;
  let escape = false;
  for (let i = 0; i < content.length; i++) {
    const c = content[i];
    if (escape) { escape = false; continue; }
    if (c === '\\') { escape = true; continue; }
    if (c === '"') { inString = !inString; continue; }
    if (!inString) {
      if (c === '{' || c === '[') depth++;
      if (c === '}' || c === ']') depth--;
    }
  }
  if (inString) content += '"';
  // Close arrays then objects
  while (depth > 0) {
    content += content.lastIndexOf('[') > content.lastIndexOf('{') ? ']' : '}';
    depth--;
  }
}

let parsed;
try {
  parsed = JSON.parse(content);
} catch(e) {
  // Fallback: generate a basic report from raw text
  parsed = {
    forecast_period: 'Current Week',
    occupancy_summary: 'Forecast generated (partial data)',
    demand_adjustments: [],
    summary: content.substring(0, 500),
    total_estimated_spend: 'N/A'
  };
}

let report = '\u{1f4ca} *WEEKLY DEMAND FORECAST* \u2014 ' + (parsed.forecast_period || 'Current Week') + '\n\n';
report += (parsed.occupancy_summary || '') + '\n\n';

const immediate = (parsed.demand_adjustments || []).filter(d => d.urgency === 'IMMEDIATE');
const thisWeek = (parsed.demand_adjustments || []).filter(d => d.urgency === 'THIS_WEEK');

if (immediate.length > 0) {
  report += '*\u{1f534} ORDER IMMEDIATELY:*\n';
  immediate.forEach(d => { report += '  ' + d.item + ': order ' + d.order_needed + ' (' + d.reason + ')\n'; });
  report += '\n';
}
if (thisWeek.length > 0) {
  report += '*\u{1f7e1} ORDER THIS WEEK:*\n';
  thisWeek.forEach(d => { report += '  ' + d.item + ': order ' + d.order_needed + ' (' + d.reason + ')\n'; });
  report += '\n';
}

report += '\u{1f4b0} Est. spend: \u20ac' + (parsed.total_estimated_spend || 'N/A') + '\n\n' + (parsed.summary || '') + '\n@controller';

const auditBody = JSON.stringify({ records: [{ fields: { reference_id: 'FORECAST-' + (parsed.forecast_period || 'unknown'), event_type: 'Approved', actor: 'System', details: 'Weekly demand forecast generated. Est. spend: \u20ac' + (parsed.total_estimated_spend || 0) } }] });

return [{ json: { report_text: report, audit_body: auditBody } }];
